class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long len = 1;
        string word = "a";
        for (int op : operations) {
            if (op == 0) {
                len *= 2;
                word += word;
            } else {
                string newWord;
                for (char c : word) {
                    if (c == 'z') newWord += 'a';
                    else newWord += (char)(c + 1);
                }
                word = newWord;
            }
        }
        return word[k % len - 1];
    }
};
